     1→import type { PointsTransaction, AppliedFilters } from '../../store/rewardProgram/models';
     2→import { TransactionType, TYPE_LABELS } from './Models';
     3→
     4→function getTransactionDescription(type: TransactionType): string {
     5→  return TYPE_LABELS[type] || '';
     6→}
     7→
     8→function matchesPeriodFilter(
     9→  transactionDate: Date,
    10→  periodStart: Date | null,
    11→  todayEnd: Date,
    12→): boolean {
    13→  if (!periodStart) return true;
    14→  return transactionDate >= periodStart && transactionDate <= todayEnd;
    15→}
    16→
    17→function matchesTypeFilter(
    18→  transactionType: string,
    19→  typesSet: Set<string> | null,
    20→): boolean {
    21→  if (!typesSet) return true;
    22→  return typesSet.has(transactionType);
    23→}
    24→
    25→export function getFilteredTransactions(
    26→  transactions: PointsTransaction[],
    27→  filters?: AppliedFilters,
    28→): PointsTransaction[] {
    29→  if (!filters || (!filters.period && (!filters.types || filters.types.length === 0))) {
    30→    return transactions;
    31→  }
    32→
    33→  const now = new Date();
    34→  const todayEnd = new Date(now);
    35→  todayEnd.setHours(23, 59, 59, 999);
    36→
    37→  const periodStart = filters.period
    38→    ? (() => {
    39→      const date = new Date(now);
    40→      date.setDate(date.getDate() - filters.period);
    41→      date.setHours(0, 0, 0, 0);
    42→      return date;
    43→    })()
    44→    : null;
    45→
    46→  const hasTypeFilter = filters.types && filters.types.length > 0;
    47→  const typesSet = hasTypeFilter ? new Set(filters.types) : null;
    48→
    49→  return transactions.filter((transaction) => {
    50→    const transactionDate = new Date(transaction.date);
    51→
    52→    if (!matchesPeriodFilter(transactionDate, periodStart, todayEnd)) {
    53→      return false;
    54→    }
    55→
    56→    if (!matchesTypeFilter(transaction.type, typesSet)) {
    57→      return false;
    58→    }
    59→
    60→    return true;
    61→  });
    62→}
    63→
    64→function matchesSearchText(
    65→  transaction: PointsTransaction,
    66→  normalizedSearch: string,
    67→  isExpiringTab: boolean,
    68→): boolean {
    69→  const amountStr = String(transaction.amount);
    70→
    71→  if (amountStr.includes(normalizedSearch)) {
    72→    return true;
    73→  }
    74→
    75→  if (isExpiringTab) {
    76→    return false;
    77→  }
    78→
    79→  const description = getTransactionDescription(transaction.type).toLowerCase();
    80→  if (description.includes(normalizedSearch)) {
    81→    return true;
    82→  }
    83→
    84→  if (transaction.description?.toLowerCase().includes(normalizedSearch)) {
    85→    return true;
    86→  }
    87→
    88→  return false;
    89→}
    90→
    91→export function getFilteredTransactionsByText(
    92→  transactions: PointsTransaction[],
    93→  searchText: string,
    94→  isExpiringTab = false,
    95→): PointsTransaction[] {
    96→  if (!searchText?.trim() || !transactions?.length) {
    97→    return transactions;
    98→  }
    99→
   100→  const normalizedSearch = searchText.toLowerCase().trim();
   101→
   102→  return transactions.filter((transaction) =>
   103→    matchesSearchText(transaction, normalizedSearch, isExpiringTab),
   104→  );
   105→}
   106→
   107→export function getPlaceholder(): string {
   108→  return 'Buscar por pontos, tipos de compra etc';
   109→}
